  function _findCached(s,e,w){
    // Exact match
    const k=s+'|'+e+'|'+(w||'');
    if(_CACHE[k])return _CACHE[k];
    const k2=s+'|'+e+'|';
    if(_CACHE[k2])return _CACHE[k2];
    // Match by range duration (daily=0d, weekly=6d, monthly~30d, yearly~365d)
    const days=Math.round((new Date(e)-new Date(s))/(86400000));
    let bestPreset='';
    if(days<=1)bestPreset='daily';
    else if(days<=8)bestPreset='weekly';
    else if(days<=35)bestPreset='monthly';
    else if(days<=95)bestPreset='quarterly';
    else bestPreset='yearly';
    // Find cache entry matching that duration pattern and WM filter
    let b=null,bd=1e15;
    for(const x of Object.keys(_CACHE)){
      const[a,c,d]=x.split('|');
      if(w&&d&&d!==w)continue;
      if(!w&&d)continue;
      const cd=Math.round((new Date(c)-new Date(a))/(86400000));
      let cp='';
      if(cd<=1)cp='daily';else if(cd<=8)cp='weekly';else if(cd<=35)cp='monthly';else if(cd<=95)cp='quarterly';else cp='yearly';
      if(cp===bestPreset)return _CACHE[x];
      const df=Math.abs(cd-days);
      if(df<bd){bd=df;b=x;}
    }
    return b?_CACHE[b]:Object.values(_CACHE)[0];
  }
